fixed_code:
use reqwest::{RequestBuilder, Client};

async fn fetch_data() -> Result<String, reqwest::Error> {
    let client = Client::new();
    let resp = client.get("https://api.example.com/data")
        .send()
        .await?;

    resp.text().await
}

#[tokio::main]
async fn main() {
    let result = fetch_data().await;
    println!("Data: {result:?}");
}

