async fn safe_add(a: u32, b: u32) -> u32 {
    let sum = a as i64 + b as i64;
    if sum < 0 || sum > u32::MAX as i64 { panic!("Overflow") }
    sum as u32
}

#[tokio::main]
async fn main() {
    let result = safe_add(1_000_000_000, 500_000_000).await;
    println!("Result: {}
", result);
}

